SELECT s.*,d.user_id as depot_user_id,u.warehouse_name
FROM `zhishu_shop_goods` s
left join t_depot d on s.depot_id = d.id
left join sys_user u on d.user_id = u.user_id


        AND s.isbn = #{isbn}


        AND s.inventory = #{inventory}


        AND s.del_flag = #{delFlag}


        AND s.is_join_distribution = #{isJoinDistribution}


        AND s.condition_code >= #{conditionCode}


order by UPPER(s.condition_code) desc,s.price asc
limit #{pageNum},#{pageSize}

mapper.update:
update zhishu_shop_goods set inventory = #{inventory},update_time = now()


        and id = #{id}


        and product_id = #{productId}


        and goods_name = #{goodsName}


        and isbn = #{isbn}


        and price = #{price}


        and condition_code = #{conditionCode}


        and fix_price = #{fixPrice}


        and art_no = #{artNo}
